import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const user = JSON.parse(localStorage.getItem("user") || "{}");

  const [requests, setRequests] = useState([]);
  const [workers, setWorkers] = useState([]);

  const [form, setForm] = useState({
    workType: "",
    labourId: "",
    labourName: "",
    location: "",
    date: ""
  });

  const jobs = ["Electrician","Plumber","Painter","Carpenter","Cleaner","Technician","Welder","Driver"];

  useEffect(() => {
    getRequests();
  }, []);

  const getRequests = async () => {
    const res = await axios.get(
      `http://localhost:5000/api/request/customer/${user.name}`
    );
    setRequests(res.data);
  };

  const searchWorkers = async (workType) => {
    const res = await axios.get("http://localhost:5000/api/auth/workers");

    setWorkers(
      res.data.filter(w => w.skills.includes(workType))
    );
  };

  const sendRequest = async () => {
    await axios.post("http://localhost:5000/api/request/send", {
      customerName: user.name,
      customerId: user._id,
      labourId: form.labourId,
      labourName: form.labourName,
      workType: form.workType,
      location: form.location,
      date: form.date,
      timings: ["9AM - 12PM"]
    });

    setForm({
      workType: "",
      labourId: "",
      labourName: "",
      location: "",
      date: ""
    });

    setWorkers([]);
    getRequests();
  };

  const submitFeedback = async (id, rating, comment) => {
    if (!rating || !comment) return alert("Fill rating & review");

    await axios.put(
      `http://localhost:5000/api/request/feedback/${id}`,
      { rating: Number(rating), comment }
    );

    setRequests(prev =>
      prev.map(r =>
        r._id === id
          ? { ...r, feedback: { rating, comment } }
          : r
      )
    );
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.wrapper}>

        {/* LEFT PANEL */}
        <div style={styles.card}>
          <h2 style={styles.title}>Hire Worker</h2>

          <select
            style={styles.input}
            value={form.workType}
            onChange={(e) => {
              setForm({ ...form, workType: e.target.value });
              searchWorkers(e.target.value);
            }}
          >
            <option>Select Work</option>
            {jobs.map(j => <option key={j}>{j}</option>)}
          </select>

          {workers.length > 0 && (
            <select
              style={styles.input}
              onChange={(e) => {
                const w = workers.find(x => x._id === e.target.value);
                setForm({
                  ...form,
                  labourId: w._id,
                  labourName: w.name
                });
              }}
            >
              <option>Select Worker</option>
              {workers.map(w => (
                <option key={w._id} value={w._id}>
                  {w.name} - {w.city}
                </option>
              ))}
            </select>
          )}

          <input
            style={styles.input}
            placeholder="Location"
            onChange={(e) => setForm({ ...form, location: e.target.value })}
          />

          <input
            type="date"
            style={styles.input}
            onChange={(e) => setForm({ ...form, date: e.target.value })}
          />

          <button style={styles.button} onClick={sendRequest}>
            Send Request
          </button>
        </div>

        {/* RIGHT PANEL */}
        <div style={styles.card}>
          <h2 style={styles.title}>My Requests</h2>

          {requests.map(req => (
            <div key={req._id} style={styles.requestCard}>

              <div style={styles.row}>
                <b>{req.labourName}</b>
                <span style={styles.badge}>{req.status}</span>
              </div>

              <p style={styles.text}>Work: {req.workType}</p>
              <p style={styles.text}>Location: {req.location}</p>
              <p style={styles.text}>Date: {req.date}</p>

              {/* STAR RATING */}
              {req.customerDecision === "Accepted" && (
                <div style={styles.ratingBox}>

                  <div style={styles.stars}>
                    {[1,2,3,4,5].map(star => (
                      <span
                        key={star}
                        style={{
                          fontSize: "22px",
                          cursor: "pointer",
                          color: (req.tempRating || 0) >= star ? "#facc15" : "#374151"
                        }}
                        onClick={() =>
                          setRequests(prev =>
                            prev.map(r =>
                              r._id === req._id
                                ? { ...r, tempRating: star }
                                : r
                            )
                          )
                        }
                      >
                        ★
                      </span>
                    ))}
                  </div>

                  <textarea
                    placeholder="Write review..."
                    style={styles.textarea}
                    onChange={(e) =>
                      setRequests(prev =>
                        prev.map(r =>
                          r._id === req._id
                            ? { ...r, tempComment: e.target.value }
                            : r
                        )
                      )
                    }
                  />

                  <button
                    style={styles.button}
                    onClick={() =>
                      submitFeedback(req._id, req.tempRating, req.tempComment)
                    }
                  >
                    Submit Rating
                  </button>

                </div>
              )}

              {req.feedback && (
                <div style={styles.saved}>
                  ⭐ {req.feedback.rating}/5
                  <p>{req.feedback.comment}</p>
                </div>
              )}

            </div>
          ))}
        </div>

      </div>
    </div>
  );
}

